using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTool
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(Name = "fetch_post"), Description("Fetches a post by ID from the external API.")]
    public static async Task<string> FetchPost(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiTool> logger,
        [Description("The numeric ID of the post to fetch (1-100).")] int id)
    {
        logger.LogInformation("Fetching post {PostId}", id);

        using var client = httpClientFactory.CreateClient("ExternalApi");
        var post = await client.GetFromJsonAsync<JsonElement>($"posts/{id}");

        return JsonSerializer.Serialize(post, JsonOptions);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum number of sentences for the summary.")] int? maxSentences = 3)
    {
